## Problem1(3.5.8.78)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "parserOneOf.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
@den = random_coprime([2..9],[2..9]);
Context("Fraction");
$m = Fraction(random_coprime([1..9], [$den[0]]));
$n = Fraction(random_coprime([1..9], [$den[1]]));
$p = $m + $n;
do {
  ($b, $c) = random_subset(2,-9..-1,1..9);
  $d = $b + $c;
} until ($d != 0);
$x = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($x => 'Real');
Context()->noreduce('(-x)+y', '(-x)-y');
$left = Formula("$m $x + $d + $n $x")->reduce;
$right = Formula("$b + $p $x + $c")->reduce;
$symbol = list_random('\lt', '\gt', '\leq', '\geq');
sub weigh {
  my ($a, $b, $s) = @_;
  if ($s eq '\lt') {return ($a < $b)}
  elsif ($s eq '\gt') {return ($a > $b)}
  elsif ($s eq '\leq') {return ($a <= $b)}
  elsif ($s eq '\geq') {return ($a >= $b)}
}
Context("FiniteSolutionSets");
$solution = (weigh($left->eval($x => 0), $right->eval($x => 0), $symbol))
  ? OneOf(Compute("R"), String("infinitely many solutions"))->cmp(typeMatch => Formula("{1}"))
  : String("no real solutions")->cmp(typeMatch => Formula("{1}"));

############################################################
# Body
############################################################

BEGIN_PGML
Solve the inequality for its variable.

[`[$left][$symbol][$right]`]

[_]{$solution}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
